            handled = true
            await sendMenuList(client, msg, jid)
            return
        }
        else if ((cmd === 'chat' || cmd === 'чат') && hasPerm(rank, 5)) {
            logger.info('execute: chat menu')
            handled = true
            await sendReply(client, msg, jid, CHAT_MENU_TEXT)
            return
