        else if ((cmd === 'demote' || cmd === 'понизь') && hasPerm(rank, 4) && target) {
            logger.info(`execute: demote ${target}`)
            handled = true
            await client.groupParticipantsUpdate(jid, [toUserJid(target)], 'demote')
            await sendReply(client, msg, jid, '📉 Участник понижен')
