const { default: makeWASocket, useMultiFileAuthState, DisconnectReason } = require('@queenanya/baileys');
const Pino = require('pino');
const fs = require('fs');
const QRCode = require('qrcode');

async function startBot() {
    const { state, saveCreds } = await useMultiFileAuthState('auth_info_master');

    const sock = makeWASocket({
        auth: state,
        printQRInTerminal: true,
        logger: Pino({ level: 'silent' }),
        browser: ['WaffenBOT', 'Chrome', '120.0.0.0'],
    });

    sock.ev.on('connection.update', async (update) => {
        const { connection, lastDisconnect, qr } = update;

        if (qr) {
            await QRCode.toFile('qr.png', qr, { width: 500 });
            console.log('\n📱 QR-код сохранён в qr.png');
            console.log('Отсканируйте QR-код в WhatsApp: Настройки → Связанные устройства\n');
        }

        if (connection === 'open') {
            console.log('✅ Бот подключен!\n');
            console.log('📝 Доступные команды:');
            console.log('   .пинг — проверить задержку бота\n');
        }

        if (connection === 'close') {
            const statusCode = lastDisconnect?.error?.output?.statusCode;
            const shouldReconnect = statusCode !== DisconnectReason.loggedOut;
            if (shouldReconnect) {
                console.log('Переподключение через 5 секунд...');
                setTimeout(() => startBot(), 5000);
            } else {
                console.log('❌ Бот вышел из системы. Удалите папку auth_info_master и перезапустите.');
            }
        }
    });

    sock.ev.on('creds.update', saveCreds);

    sock.ev.on('messages.upsert', async ({ messages }) => {
        const msg = messages[0];
        if (!msg.message) return;

        const nowTime = Math.floor(Date.now() / 1000);
        const isOld = (nowTime - msg.messageTimestamp) > 3;
        if (isOld) return;

        const jid = msg.key.remoteJid;
        const sender = msg.key.participant || jid;

        let text = msg.message?.conversation || msg.message?.extendedTextMessage?.text || '';
        if (!text) return;

        const lowerText = text.trim().toLowerCase();

        // ========== КОМАНДЫ ==========

        // Команда .пинг
        if (lowerText === '.пинг' || lowerText === '.ping') {
            const startTime = Date.now();

            const sentMsg = await sock.sendMessage(jid, { text: '🏓 Понг!' });

            const endTime = Date.now();
            const pingMs = endTime - startTime;

            await sock.sendMessage(jid, {
                text: `🏓 Понг! \n⏱️ ${pingMs} мс`,
                edit: sentMsg.key
            });
            return;
        }
    });

    console.log('🤖 Бот запущен...\n');
}

startBot().catch(console.error);

sock.ev.on('messages.upsert', async ({ messages }) => {
  for (const msg of messages) {
    if (!msg.message) continue;

    const jid = msg.key.remoteJid;
    const interactive = msg.message.interactiveResponseMessage;

    if (interactive) {
      // В новых версиях WhatsApp ответ приходит в nativeFlowResponseMessage или selectedId
      const btnId = interactive.nativeFlowResponseMessage?.selectedButtonId || 
                    interactive.selectedId || 
                    JSON.parse(interactive.nativeFlowResponseMessage?.paramsJson || '{}')?.id;

      if (!btnId) continue;

      switch (btnId) {
        case 'status':
          await sock.sendMessage(jid, { text: '📊 Статус: активен' });
          break;
        case 'help':
          await sock.sendMessage(jid, { text: '📖 Используйте меню или напишите команду.' });
          break;
        case 'exit':
          await sock.sendMessage(jid, { text: '👋 Сессия завершена.' });
          break;
      }
    }
  }
});
